#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char best_id[21] = "";
        double best_temp = -1e18;
        for (int i = 0; i < N; ++i) {
            char id[21]; double temp; int hum; double wind;
            scanf("%s %lf %d %lf", id, &temp, &hum, &wind);
            if (temp > best_temp) {
                best_temp = temp;
                strcpy(best_id, id);
            }
        }
        printf("Hottest station: %s\n", best_id);
    }
    return 0;
}

