code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            int N = Integer.parseInt(br.readLine().trim());
            String bestId = "";
            double bestTemp = -1e18;
            for (int i = 0; i < N; ++i) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                String id = st.nextToken();
                double temp = Double.parseDouble(st.nextToken());
                st.nextToken(); // humidity, not needed for decision
                st.nextToken(); // wind speed, not needed for decision
                if (temp > bestTemp) {
                    bestTemp = temp;
                    bestId = id;
                }
            }
            sb.append("Hottest station: ").append(bestId);
            if (tc != T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

