from dataclasses import dataclass
import sys

@dataclass
class WeatherData:
    station_id: str
    temperature: float
    humidity: int
    wind_speed: float

def find_hottest_station(stations):
    best = stations[0]
    for s in stations[1:]:
        if s.temperature > best.temperature:
            best = s
    return best.station_id

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        stations = []
        for _ in range(N):
            parts = next(it).split()
            stations.append(WeatherData(parts[0], float(parts[1]), int(parts[2]), float(parts[3])))
        out.append(f"Hottest station: {find_hottest_station(stations)}")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

